local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst     self.old_level = -1     if TD.ds() then                  TD.latter(self.inst, 0.1, function()             self:flush()         end)     end end) function myComponent:flush()     local inst = self.inst          TD.flushAtt(inst, {         speed = self:getSpeed()     })     local lv = math.floor(TD.csv(inst):get(TD.holder("%s_lv")))          TD.player(inst, function()                  local exp = math.floor(TD.csv(inst):get(TD.holder("%s_exp")))                  if inst.setLv then             inst.setLv(lv)         end         local base = TD.baseExp(lv, exp)         if inst.setExp then             inst.setExp(exp, base)         end     end)          TD.server(function()                  if self.old_level ~= lv then                          local arr = {}             arr.health = TD.setMin(TD.CONST.MAX_HEALTH * (1 + 0.03 * (lv - 1)), 27500)             arr.hunger = TD.setMin(TD.CONST.MAX_HUNGER * (1 + 0.03 * (lv - 1)), 300)             arr.sanity = TD.setMin(TD.CONST.MAX_SANITY * (1 + 0.03 * (lv - 1)), 27420)             arr.damage = 1 + 0.02 * (lv - 1)             TD.flushAtt(inst, arr)             self.old_level = lv         end     end) end function myComponent:getSpeed()     return 1.3 end return myComponent 